batch_norm.metal_source:
// batchnorm: normalize each column over rows. (1024, 256) input.
// Strided simdgroup reduction over 1024 elements per column.
#include <metal_stdlib>
using namespace metal;

kernel void batch_norm_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     uint&   C       [[buffer(3)]],
    constant     float&  eps     [[buffer(4)]],
    uint3 tid                   [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint col = tgid.y;

    float val = x[t * C + col];
    float s2  = val * val;

    float sum   = simd_sum(val);
    float sumsq = simd_sum(s2);

    threadgroup float tg_sum[32];
    threadgroup float tg_sumsq[32];
    const uint sg = t >> 5;
    if ((t & 31) == 0) {
        tg_sum[sg]   = sum;
        tg_sumsq[sg] = sumsq;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (t < 32) {
        sum   = tg_sum[t];
        sumsq = tg_sumsq[t];
        for (uint s = 16; s > 0; s >>= 1) {
            sum   += simd_shuffle_down(sum,   s);
            sumsq += simd_shuffle_down(sumsq, s);
        }
    }
    if (t == 0) {
        tg_sum[0]   = sum;
        tg_sumsq[0] = sumsq;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float mean = tg_sum[0] / float(N);
    float var  = max(tg_sumsq[0] / float(N) - mean * mean, 0.0f);
    float inv_std = rsqrt(var + eps);

    y[t * C + col] = (val - mean) * inv_std;
}

elu.metal_source:
// elu: x if x>0 else α*(exp(x)-1). 1024 thr/tg, float4, grid-stride.
#include <metal_stdlib>
using namespace metal;

kernel void elu_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    constant     float&  alpha     [[buffer(4)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *reinterpret_cast<const device float4*>(&x[i * 4]);
        // Use min(v,0) to feed exp — avoids huge exp for large positive v.
        float4 neg = alpha * (exp(min(v, float4(0.0f))) - 1.0f);
        float4 out = select(neg, v, v > 0.0f);
        *reinterpret_cast<device float4*>(&y[i * 4]) = out;
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        float v = x[i];
        y[i] = v > 0.0f ? v : alpha * (exp(v) - 1.0f);
    }
}

mish.metal_source:
// mish: x * tanh(softplus(x)). Stable softplus = max(x,0) + log1p(exp(-|x|)).
#include <metal_stdlib>
using namespace metal;

static inline float4 softplus4(float4 v) {
    float4 ax = fabs(v);
    float4 mx = fmax(v, 0.0f);
    return mx + log(1.0f + exp(-ax));
}

kernel void mish_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *reinterpret_cast<const device float4*>(&x[i * 4]);
        float4 sp = softplus4(v);
        *reinterpret_cast<device float4*>(&y[i * 4]) = v * tanh(sp);
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        float v = x[i];
        float sp = fmax(v, 0.0f) + log(1.0f + exp(-fabs(v)));
        y[i] = v * tanh(sp);
    }
}

softplus.metal_source:
// softplus: log(1 + exp(x)). Stable form: max(x,0) + log1p(exp(-|x|)).
#include <metal_stdlib>
using namespace metal;

kernel void softplus_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *reinterpret_cast<const device float4*>(&x[i * 4]);
        float4 ax = fabs(v);
        float4 mx = fmax(v, 0.0f);
        *reinterpret_cast<device float4*>(&y[i * 4]) = mx + log(1.0f + exp(-ax));
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        float v = x[i];
        y[i] = fmax(v, 0.0f) + log(1.0f + exp(-fabs(v)));
    }
}

prelu.metal_source:
// prelu: x if x>0 else alpha[c]*x. Per-channel slope.
// Shape: x is (N, C), alpha is (C,). Layout assumed row-major: x[n*C + c].
#include <metal_stdlib>
using namespace metal;

kernel void prelu_f32(
    device const float*  x         [[buffer(0)]],
    device const float*  alpha     [[buffer(1)]],
    device       float*  y         [[buffer(2)]],
    constant     uint&   N_total   [[buffer(3)]],
    constant     uint&   C         [[buffer(4)]],
    constant     uint&   grid_size [[buffer(5)]],
    uint  tid                     [[thread_position_in_grid]])
{
    for (uint i = tid; i < N_total; i += grid_size) {
        float v = x[i];
        uint c = i % C;
        float a = alpha[c];
        y[i] = v > 0.0f ? v : a * v;
    }
}

argmax.metal_source:
// argmax: per-row argmax along last dim. One threadgroup per row.
// Input (R, C). Output index as float (harness expects f32 outputs).
#include <metal_stdlib>
using namespace metal;

kernel void argmax_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  out     [[buffer(1)]],
    constant     uint&   C       [[buffer(2)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint row = tgid.y;
    device const float* row_ptr = x + row * C;

    float best_v = -INFINITY;
    uint  best_i = 0;
    for (uint i = tid; i < C; i += TG) {
        float v = row_ptr[i];
        if (v > best_v) { best_v = v; best_i = i; }
    }

    threadgroup float tg_v[32];
    threadgroup uint  tg_i[32];

    // Simdgroup reduction: pick max-value lane, propagate its index.
    for (uint s = 16; s > 0; s >>= 1) {
        float ov = simd_shuffle_down(best_v, s);
        uint  oi = simd_shuffle_down(best_i, s);
        if (ov > best_v) { best_v = ov; best_i = oi; }
    }
    uint sg = tid >> 5;
    if ((tid & 31) == 0) { tg_v[sg] = best_v; tg_i[sg] = best_i; }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (tid < 32) {
        best_v = tg_v[tid];
        best_i = tg_i[tid];
        for (uint s = 16; s > 0; s >>= 1) {
            float ov = simd_shuffle_down(best_v, s);
            uint  oi = simd_shuffle_down(best_i, s);
            if (ov > best_v) { best_v = ov; best_i = oi; }
        }
        if (tid == 0) out[row] = float(best_i);
    }
}

variance.metal_source:
// variance: per-row Var(x) = mean(x²) − mean(x)². One threadgroup per row.
#include <metal_stdlib>
using namespace metal;

kernel void variance_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  out     [[buffer(1)]],
    constant     uint&   C       [[buffer(2)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint tid = tid3.x;
    const uint row = tgid.y;
    device const float* row_ptr = x + row * C;
    const uint sg = tid >> 5;
    const uint lane = tid & 31;

    float v = row_ptr[tid];
    float sum   = simd_sum(v);
    float sumsq = simd_sum(v * v);

    threadgroup float tg_s[32], tg_q[32];
    if (lane == 0) { tg_s[sg] = sum; tg_q[sg] = sumsq; }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (sg == 0) {
        float s  = tg_s[lane];
        float sq = tg_q[lane];
        s  = simd_sum(s);
        sq = simd_sum(sq);
        if (lane == 0) {
            float mean = s / float(C);
            out[row] = sq / float(C) - mean * mean;
        }
    }
}

rope_embedding.metal_source:
// rope_embedding: rotary position embedding. Input (S, D), D even.
// Per (s, i) where i in [0, D/2): rotate pair (x[s,2i], x[s,2i+1]).
#include <metal_stdlib>
using namespace metal;

kernel void rope_embedding_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   S         [[buffer(2)]],
    constant     uint&   D         [[buffer(3)]],
    constant     float&  base      [[buffer(4)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint half_d = D / 2;
    const uint total  = S * half_d;
    if (tid >= total) return;

    const uint s = tid / half_d;
    const uint i = tid % half_d;
    float omega = 1.0f / pow(base, (2.0f * float(i)) / float(D));
    float ang = float(s) * omega;
    float c = cos(ang), sn = sin(ang);

    float x0 = x[s * D + 2 * i];
    float x1 = x[s * D + 2 * i + 1];
    y[s * D + 2 * i]     = x0 * c - x1 * sn;
    y[s * D + 2 * i + 1] = x0 * sn + x1 * c;
}

swiglu.metal_source:
// swiglu: silu(x @ W_gate) * (x @ W_up).
// One thread per output element. Output (M, N).
#include <metal_stdlib>
using namespace metal;

kernel void swiglu_f32(
    device const float*  X       [[buffer(0)]],
    device const float*  Wg      [[buffer(1)]],
    device const float*  Wu      [[buffer(2)]],
    device       float*  Y       [[buffer(3)]],
    constant     uint&   M       [[buffer(4)]],
    constant     uint&   N       [[buffer(5)]],
    constant     uint&   K       [[buffer(6)]],
    uint  tid                   [[thread_position_in_grid]])
{
    if (tid >= M * N) return;
    const uint m = tid / N;
    const uint n = tid % N;

    float g = 0.0f, u = 0.0f;
    for (uint k = 0; k < K; ++k) {
        float xk = X[m * K + k];
        g += xk * Wg[k * N + n];
        u += xk * Wu[k * N + n];
    }
    float silu_g = g / (1.0f + exp(-g));
    Y[m * N + n] = silu_g * u;
}

softmax_attention.metal_source:
// softmax_attention: softmax(Q @ K^T / sqrt(D)) @ V. S=128, D=64.
// One TG per query row. TG=1024.
#include <metal_stdlib>
using namespace metal;

kernel void softmax_attention_f32(
    device const float*  Q       [[buffer(0)]],
    device const float*  K       [[buffer(1)]],
    device const float*  V       [[buffer(2)]],
    device       float*  O       [[buffer(3)]],
    constant     uint&   S       [[buffer(4)]],
    constant     uint&   D       [[buffer(5)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint qr = tgid.y;
    if (qr >= S) return;

    threadgroup float qrow[64];
    threadgroup float scores[128];
    threadgroup float reduce[32];

    // Load Q row
    if (tid < D) qrow[tid] = Q[qr * D + tid];
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const float inv = rsqrt(float(D));

    // Q @ K^T: 128 scores. Use 8 threads per score (D=64 / 8 = 8 elems each).
    // tid = j * 8 + sub, j in [0,128), sub in [0,8). Use tid < 1024 = S*8.
    {
        uint j = tid >> 3;        // 0..127
        uint sub = tid & 7;       // 0..7
        uint d0 = sub * 8;
        float acc = 0.0f;
        device const float* kr = K + j * D;
        for (uint dd = 0; dd < 8; ++dd) acc += qrow[d0 + dd] * kr[d0 + dd];
        // 8 lanes within same simd group hold partial sums for one j.
        // Their tid's are contiguous: j*8..j*8+7. simd_shuffle_xor with mask 4,2,1 reduces them.
        acc += simd_shuffle_xor(acc, 1);
        acc += simd_shuffle_xor(acc, 2);
        acc += simd_shuffle_xor(acc, 4);
        if (sub == 0) scores[j] = acc * inv;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Row max
    float v = (tid < S) ? scores[tid] : -INFINITY;
    float mx = simd_max(v);
    uint sg = tid >> 5;
    uint lane = tid & 31;
    if (lane == 0) reduce[sg] = mx;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (sg == 0) {
        float m = (lane < 4) ? reduce[lane] : -INFINITY;
        m = simd_max(m);
        if (lane == 0) reduce[0] = m;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float row_max = reduce[0];

    // Exp + sum
    float e = (tid < S) ? fast::exp(scores[tid] - row_max) : 0.0f;
    if (tid < S) scores[tid] = e;
    float sum = simd_sum(e);
    if (lane == 0) reduce[sg] = sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (sg == 0) {
        float s = (lane < 4) ? reduce[lane] : 0.0f;
        s = simd_sum(s);
        if (lane == 0) reduce[0] = s;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float inv_sum = 1.0f / reduce[0];
    if (tid < S) scores[tid] = scores[tid] * inv_sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Output: O[qr, d] = sum_j scores[j] * V[j, d]. D=64, S=128.
    // Use all 1024 = 16 lanes per d. Each lane processes S/16 = 8 j's.
    {
        uint d = tid & 63;
        uint j_lane = tid >> 6;   // 0..15
        uint j_start = j_lane * 8;
        float acc = 0.0f;
        for (uint j = j_start; j < j_start + 8; ++j) acc += scores[j] * V[j * D + d];
        // Reduce across 16 j_lane values for same d.
        // For each d (0..63), there are 16 threads at tid = j_lane*64+d.
        // These are at strided lane positions within simdgroups; use TG memory.
        threadgroup float tmp[64 * 16];
        tmp[d * 16 + j_lane] = acc;
        threadgroup_barrier(mem_flags::mem_threadgroup);
        if (j_lane == 0) {
            float s = 0.0f;
            for (uint k = 0; k < 16; ++k) s += tmp[d * 16 + k];
            O[qr * D + d] = s;
        }
    }
}

residual_add.metal_source:
// residual_add: y = x + alpha * residual. Vectorized: single float4 per thread.
#include <metal_stdlib>
using namespace metal;

kernel void residual_add_f32(
    device const float*  X       [[buffer(0)]],
    device const float*  R       [[buffer(1)]],
    device       float*  Y       [[buffer(2)]],
    constant     uint&   N       [[buffer(3)]],
    constant     uint&   grid_size [[buffer(4)]],
    constant     float&  alpha   [[buffer(5)]],
    uint tid                    [[thread_position_in_grid]])
{
    // N = 1024*1024 = 1<<20. grid_size = 64*1024 = 1<<16.
    // Each thread does N/grid_size = 16 floats = 4 float4s.
    const uint n4 = N >> 2;           // 1<<18
    const float a = alpha;
    // Use base = tid*4 then stride grid_size in float4 units.
    for (uint i = tid; i < n4; i += grid_size) {
        uint base = i << 2;
        float4 x = *reinterpret_cast<const device float4*>(&X[base]);
        float4 r = *reinterpret_cast<const device float4*>(&R[base]);
        *reinterpret_cast<device float4*>(&Y[base]) = x + a * r;
    }
}

dropout.metal_source:
// dropout (inverted): y = mask * x * (1/(1-p)). float4 grid-stride.
#include <metal_stdlib>
using namespace metal;

kernel void dropout_f32(
    device const float*  X       [[buffer(0)]],
    device const float*  M       [[buffer(1)]],
    device       float*  Y       [[buffer(2)]],
    constant     uint&   N       [[buffer(3)]],
    constant     uint&   grid_size [[buffer(4)]],
    constant     float&  p       [[buffer(5)]],
    uint tid                    [[thread_position_in_grid]])
{
    const float scale = 1.0f / (1.0f - p);
    const uint n4 = N >> 2;
    for (uint i = tid; i < n4; i += grid_size) {
        uint base = i << 2;
        float4 x = *reinterpret_cast<const device float4*>(&X[base]);
        float4 m = *reinterpret_cast<const device float4*>(&M[base]);
        *reinterpret_cast<device float4*>(&Y[base]) = m * x * scale;
    }
}

instance_norm.metal_source:
// instance_norm: normalize per-sample per-channel over (H, W).
// Layout (N, C, H, W). One threadgroup per (n, c) block, reduces H*W elements.
#include <metal_stdlib>
using namespace metal;

kernel void instance_norm_f32(
    device const float*  X       [[buffer(0)]],
    device       float*  Y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     uint&   C       [[buffer(3)]],
    constant     uint&   H       [[buffer(4)]],
    constant     uint&   W       [[buffer(5)]],
    constant     float&  eps     [[buffer(6)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint nc = tgid.y;
    const uint HW = H * W;
    device const float* base_in  = X + nc * HW;
    device       float* base_out = Y + nc * HW;

    float sum = 0.0f, sumsq = 0.0f;
    for (uint i = tid; i < HW; i += TG) {
        float v = base_in[i];
        sum   += v;
        sumsq += v * v;
    }
    sum   = simd_sum(sum);
    sumsq = simd_sum(sumsq);

    threadgroup float tg_s[32], tg_q[32];
    uint sg = tid >> 5;
    if ((tid & 31) == 0) { tg_s[sg] = sum; tg_q[sg] = sumsq; }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (tid < 32) {
        sum   = tg_s[tid];
        sumsq = tg_q[tid];
        for (uint s = 16; s > 0; s >>= 1) {
            sum   += simd_shuffle_down(sum,   s);
            sumsq += simd_shuffle_down(sumsq, s);
        }
        if (tid == 0) { tg_s[0] = sum; tg_q[0] = sumsq; }
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float mean = tg_s[0] / float(HW);
    float var  = max(tg_q[0] / float(HW) - mean * mean, 0.0f);
    float inv  = rsqrt(var + eps);
    for (uint i = tid; i < HW; i += TG)
        base_out[i] = (base_in[i] - mean) * inv;
}

group_norm.metal_source:
// group_norm: normalize per-sample per-group over (CG, H, W) where CG = C/G.
// One threadgroup per (n, g) block, reduces CG*H*W elements.
#include <metal_stdlib>
using namespace metal;

kernel void group_norm_f32(
    device const float*  X       [[buffer(0)]],
    device       float*  Y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     uint&   C       [[buffer(3)]],
    constant     uint&   H       [[buffer(4)]],
    constant     uint&   W       [[buffer(5)]],
    constant     uint&   G       [[buffer(6)]],
    constant     float&  eps     [[buffer(7)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint ng  = tgid.y;     // 0 .. N*G - 1
    const uint n   = ng / G;
    const uint g   = ng % G;
    const uint CG  = C / G;
    const uint block = CG * H * W;
    device const float* base_in  = X + (n * C + g * CG) * H * W;
    device       float* base_out = Y + (n * C + g * CG) * H * W;

    float sum = 0.0f, sumsq = 0.0f;
    for (uint i = tid; i < block; i += TG) {
        float v = base_in[i];
        sum   += v;
        sumsq += v * v;
    }
    sum   = simd_sum(sum);
    sumsq = simd_sum(sumsq);

    threadgroup float tg_s[32], tg_q[32];
    uint sg = tid >> 5;
    if ((tid & 31) == 0) { tg_s[sg] = sum; tg_q[sg] = sumsq; }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        sum   = tg_s[tid];
        sumsq = tg_q[tid];
        for (uint s = 16; s > 0; s >>= 1) {
            sum   += simd_shuffle_down(sum,   s);
            sumsq += simd_shuffle_down(sumsq, s);
        }
        if (tid == 0) { tg_s[0] = sum; tg_q[0] = sumsq; }
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float mean = tg_s[0] / float(block);
    float var  = max(tg_q[0] / float(block) - mean * mean, 0.0f);
    float inv  = rsqrt(var + eps);
    for (uint i = tid; i < block; i += TG)
        base_out[i] = (base_in[i] - mean) * inv;
}

cross_entropy_loss.metal_source:
// cross_entropy_loss: per-row -sum(y_onehot * log_softmax(logits)).
// Output shape (N,). One threadgroup per row.
#include <metal_stdlib>
using namespace metal;

kernel void cross_entropy_loss_f32(
    device const float*  L        [[buffer(0)]],   // logits (N, C)
    device const float*  Yh       [[buffer(1)]],   // one-hot (N, C)
    device       float*  out      [[buffer(2)]],   // (N,)
    constant     uint&   N        [[buffer(3)]],
    constant     uint&   C        [[buffer(4)]],
    uint3 tid3                   [[thread_position_in_threadgroup]],
    uint3 tgid                   [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint row = tgid.y;
    device const float* lp = L  + row * C;
    device const float* yp = Yh + row * C;

    threadgroup float reduce[32];

    float mx = -INFINITY;
    for (uint i = tid; i < C; i += TG) mx = fmax(mx, lp[i]);
    mx = simd_max(mx);
    if ((tid & 31) == 0) reduce[tid >> 5] = mx;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        mx = reduce[tid];
        for (uint s = 16; s > 0; s >>= 1) mx = fmax(mx, simd_shuffle_down(mx, s));
        if (tid == 0) reduce[0] = mx;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float row_max = reduce[0];

    float sum = 0.0f;
    for (uint i = tid; i < C; i += TG) sum += exp(lp[i] - row_max);
    sum = simd_sum(sum);
    if ((tid & 31) == 0) reduce[tid >> 5] = sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        sum = reduce[tid];
        for (uint s = 16; s > 0; s >>= 1) sum += simd_shuffle_down(sum, s);
        if (tid == 0) reduce[0] = sum;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float lse = row_max + log(reduce[0]);

    float nll = 0.0f;
    for (uint i = tid; i < C; i += TG) nll += yp[i] * (lse - lp[i]);
    nll = simd_sum(nll);
    if ((tid & 31) == 0) reduce[tid >> 5] = nll;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        nll = reduce[tid];
        for (uint s = 16; s > 0; s >>= 1) nll += simd_shuffle_down(nll, s);
        if (tid == 0) out[row] = nll;
    }
}

log_softmax.metal_source:
// log_softmax: y = x - logsumexp(x). One TG per row.
#include <metal_stdlib>
using namespace metal;

kernel void log_softmax_f32(
    device const float*  X       [[buffer(0)]],
    device       float*  Y       [[buffer(1)]],
    constant     uint&   C       [[buffer(2)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint row = tgid.y;
    device const float* xr = X + row * C;
    device       float* yr = Y + row * C;

    threadgroup float reduce[32];

    float mx = -INFINITY;
    for (uint i = tid; i < C; i += TG) {
        float v = xr[i];
        yr[i] = v;  // stash for reuse
        mx = fmax(mx, v);
    }
    mx = simd_max(mx);
    if ((tid & 31) == 0) reduce[tid >> 5] = mx;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        mx = simd_max(reduce[tid]);
        if (tid == 0) reduce[0] = mx;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float row_max = reduce[0];

    float sum = 0.0f;
    for (uint i = tid; i < C; i += TG) sum += fast::exp(yr[i] - row_max);
    sum = simd_sum(sum);
    if ((tid & 31) == 0) reduce[tid >> 5] = sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        sum = simd_sum(reduce[tid]);
        if (tid == 0) reduce[0] = sum;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float lse = row_max + fast::log(reduce[0]);

    for (uint i = tid; i < C; i += TG) yr[i] = yr[i] - lse;
}

masked_softmax.metal_source:
// masked_softmax: y = softmax(x + mask). Per-row. Assumes C == TG = 1024.
#include <metal_stdlib>
using namespace metal;

kernel void masked_softmax_f32(
    device const float*  X       [[buffer(0)]],
    device const float*  M       [[buffer(1)]],
    device       float*  Y       [[buffer(2)]],
    constant     uint&   C       [[buffer(3)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint t = tid3.x;
    const uint row = tgid.y;
    const uint off = row * C;
    const uint lane = t & 31u;
    const uint sg = t >> 5;

    threadgroup float tg_buf[32];
    threadgroup float row_max;
    threadgroup float row_sum;

    float val = X[off + t] + M[off + t];

    // max
    float m = simd_max(val);
    if (lane == 0) tg_buf[sg] = m;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (sg == 0) {
        float v = tg_buf[lane];
        v = simd_max(v);
        if (lane == 0) row_max = v;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float rmax = row_max;

    // exp + sum
    float ev = exp(val - rmax);
    float s = simd_sum(ev);
    if (lane == 0) tg_buf[sg] = s;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (sg == 0) {
        float v = tg_buf[lane];
        v = simd_sum(v);
        if (lane == 0) row_sum = v;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    Y[off + t] = ev / row_sum;
}

bias_add.metal_source:
// bias_add: y[r, c] = x[r, c] + b[c]. float4 grid-stride loop.
#include <metal_stdlib>
using namespace metal;

kernel void bias_add_f32(
    device const float*  X        [[buffer(0)]],
    device const float*  B        [[buffer(1)]],
    device       float*  Y        [[buffer(2)]],
    constant     uint&   N_total  [[buffer(3)]],
    constant     uint&   C        [[buffer(4)]],
    constant     uint&   grid_size [[buffer(5)]],
    uint tid                     [[thread_position_in_grid]])
{
    const uint n4 = N_total >> 2;
    const uint Cmask = C - 1; // C is 1024
    for (uint i = tid; i < n4; i += grid_size) {
        uint base = i << 2;
        float4 x = *reinterpret_cast<const device float4*>(&X[base]);
        float4 b = *reinterpret_cast<const device float4*>(&B[base & Cmask]);
        *reinterpret_cast<device float4*>(&Y[base]) = x + b;
    }
}

fused_add_rms_norm.metal_source:
// fused_add_rms_norm: y = (x+r) * rsqrt(mean((x+r)^2) + eps). Per-row.
#include <metal_stdlib>
using namespace metal;

kernel void fused_add_rms_norm_f32(
    device const float*  X       [[buffer(0)]],
    device const float*  R       [[buffer(1)]],
    device       float*  Y       [[buffer(2)]],
    constant     uint&   D       [[buffer(3)]],
    constant     float&  eps     [[buffer(4)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint row = tgid.y;
    device const float* xr = X + row * D;
    device const float* rr = R + row * D;
    device       float* yr = Y + row * D;

    threadgroup float reduce[32];

    float sumsq = 0.0f;
    for (uint i = tid; i < D; i += TG) {
        float v = xr[i] + rr[i];
        sumsq += v * v;
    }
    sumsq = simd_sum(sumsq);
    if ((tid & 31) == 0) reduce[tid >> 5] = sumsq;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        sumsq = reduce[tid];
        for (uint s = 16; s > 0; s >>= 1) sumsq += simd_shuffle_down(sumsq, s);
        if (tid == 0) reduce[0] = sumsq;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float inv = rsqrt(reduce[0] / float(D) + eps);
    for (uint i = tid; i < D; i += TG) yr[i] = (xr[i] + rr[i]) * inv;
}

linear_bias.metal_source:
// linear_bias: y = x @ W + b. (M,K) @ (K,N) + (N,). M=N=K=256.
// Grid: 1D, 256 thr/tg. Each TG processes 256 contiguous output elements
// — exactly one full row of N=256 outputs.
#include <metal_stdlib>
using namespace metal;

kernel void linear_bias_f32(
    device const float*  X        [[buffer(0)]],
    device const float*  W        [[buffer(1)]],
    device const float*  B        [[buffer(2)]],
    device       float*  Y        [[buffer(3)]],
    constant     uint&   M        [[buffer(4)]],
    constant     uint&   N        [[buffer(5)]],
    constant     uint&   K        [[buffer(6)]],
    uint tid                     [[thread_position_in_grid]],
    uint lid                     [[thread_position_in_threadgroup]],
    uint tgid                    [[threadgroup_position_in_grid]])
{
    threadgroup float xrow[256];     // K = 256
    threadgroup float brow[256];     // N = 256
    const uint m = tgid;             // row index
    if (m >= M) return;

    // Cooperatively load X row (K=256) and bias (N=256). Both 256 floats with 256 threads.
    xrow[lid] = X[m * K + lid];
    brow[lid] = B[lid];
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Each thread computes one output col n = lid.
    const uint n = lid;
    float acc = brow[n];
    #pragma unroll(8)
    for (uint k = 0; k < K; ++k) acc += xrow[k] * W[k * N + n];
    Y[m * N + n] = acc;
}

bias_gelu.metal_source:
// bias_gelu: y = gelu(x + b). float4 with cached bias in threadgroup memory.
// Uses tanh-approximation of GELU for speed.
#include <metal_stdlib>
using namespace metal;

constant constexpr float gelu_k = 0.79788456f; // sqrt(2/pi)

static inline float4 gelu_tanh4(float4 v) {
    float4 t = gelu_k * (v + 0.044715f * v * v * v);
    return 0.5f * v * (1.0f + tanh(t));
}

kernel void bias_gelu_f32(
    device const float*  X        [[buffer(0)]],
    device const float*  B        [[buffer(1)]],
    device       float*  Y        [[buffer(2)]],
    constant     uint&   N_total  [[buffer(3)]],
    constant     uint&   C        [[buffer(4)]],
    constant     uint&   grid_size [[buffer(5)]],
    uint tid                       [[thread_position_in_grid]],
    uint lid                       [[thread_position_in_threadgroup]],
    uint tg_size                   [[threads_per_threadgroup]])
{
    threadgroup float bias_tg[1024];
    for (uint i = lid; i < C; i += tg_size) bias_tg[i] = B[i];
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const uint n4 = N_total >> 2;
    const uint Cmask = C - 1;
    for (uint i = tid; i < n4; i += grid_size) {
        uint base = i << 2;
        float4 x = *reinterpret_cast<const device float4*>(&X[base]);
        float4 b = *reinterpret_cast<const threadgroup float4*>(&bias_tg[base & Cmask]);
        float4 z = x + b;
        *reinterpret_cast<device float4*>(&Y[base]) = gelu_tanh4(z);
    }
}

fused_qkv_projection.metal_source:
// fused_qkv_projection: y = x @ W. (M, K) @ (K, N).
// M=128, N=192, K=512. Tiled: each TG (256 threads) computes a BM x BN output block.
#include <metal_stdlib>
using namespace metal;

constant constexpr uint BM = 16;
constant constexpr uint BN = 16;
constant constexpr uint BK = 16;
constant constexpr uint TG_SIZE = 256;
constant constexpr uint TILES_N = 192 / BN;   // 12

kernel void fused_qkv_projection_f32(
    device const float*  X        [[buffer(0)]],
    device const float*  W        [[buffer(1)]],
    device       float*  Y        [[buffer(2)]],
    constant     uint&   M        [[buffer(3)]],   // 128
    constant     uint&   N        [[buffer(4)]],   // 192
    constant     uint&   K        [[buffer(5)]],   // 512
    uint  tgid_lin               [[threadgroup_position_in_grid]],
    uint  lid                    [[thread_index_in_threadgroup]])
{
    // Map linear tg to (tile_m, tile_n). 8 x 12 = 96 tiles.
    const uint tm = tgid_lin / TILES_N;
    const uint tn = tgid_lin % TILES_N;
    if (tm * BM >= M) return;

    const uint row_block = tm * BM;
    const uint col_block = tn * BN;

    // Each thread owns one output (lm, ln) in the BM x BN tile.
    const uint lm = lid / BN;   // 0..15
    const uint ln = lid % BN;   // 0..15

    threadgroup float Xs[BM * BK];   // 256 floats
    threadgroup float Ws[BK * BN];   // 256 floats

    float acc = 0.0f;
    const uint num_k = K / BK;  // 32
    for (uint kt = 0; kt < num_k; ++kt) {
        const uint k0 = kt * BK;
        // Cooperative load: 256 threads, 256 floats each tile. 1 element/thread.
        // Xs[lm, kc]  <- X[row_block+lm, k0+kc]  with idx = lm*BK + kc, lid = lm*BN + ln, BN=BK=16.
        Xs[lid] = X[(row_block + lm) * K + k0 + ln];   // ln serves as kc
        // Ws[kc, ln] <- W[k0+kc, col_block+ln]; idx = lm*BN+ln corresponds to kc=lm, ln=ln
        Ws[lid] = W[(k0 + lm) * N + col_block + ln];
        threadgroup_barrier(mem_flags::mem_threadgroup);

        #pragma unroll
        for (uint kc = 0; kc < BK; ++kc) {
            acc += Xs[lm * BK + kc] * Ws[kc * BN + ln];
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
    }

    Y[(row_block + lm) * N + (col_block + ln)] = acc;
}

attention_scores.metal_source:
// attention_scores: softmax(Q @ K^T / sqrt(D)).
// One TG per query row. S=128, D=64. TG = 1024 threads, but only first 128 do work.
#include <metal_stdlib>
using namespace metal;

kernel void attention_scores_f32(
    device const float*  Q       [[buffer(0)]],
    device const float*  K       [[buffer(1)]],
    device       float*  O       [[buffer(2)]],
    constant     uint&   S       [[buffer(3)]],
    constant     uint&   D       [[buffer(4)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint qr = tgid.y;
    if (qr >= S) return;

    threadgroup float qrow[64];      // D up to 64
    threadgroup float scores[128];   // S up to 128
    threadgroup float reduce[32];

    // Cooperatively load Q row.
    for (uint d = tid; d < D; d += TG) qrow[d] = Q[qr * D + d];
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float inv = rsqrt(float(D));
    // Each of first S threads computes one score.
    if (tid < S) {
        device const float* kr = K + tid * D;
        float dot = 0.0f;
        for (uint d = 0; d < D; ++d) dot += qrow[d] * kr[d];
        scores[tid] = dot * inv;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Row max over S=128 elements.
    float v = (tid < S) ? scores[tid] : -INFINITY;
    float mx = simd_max(v);
    if ((tid & 31) == 0) reduce[tid >> 5] = mx;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        // 128/32 = 4 valid lanes
        float m = (tid < 4) ? reduce[tid] : -INFINITY;
        m = simd_max(m);
        if (tid == 0) reduce[0] = m;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float row_max = reduce[0];

    float e = (tid < S) ? fast::exp(scores[tid] - row_max) : 0.0f;
    if (tid < S) scores[tid] = e;
    float sum = simd_sum(e);
    if ((tid & 31) == 0) reduce[tid >> 5] = sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        float s = (tid < 4) ? reduce[tid] : 0.0f;
        s = simd_sum(s);
        if (tid == 0) reduce[0] = s;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float inv_sum = 1.0f / reduce[0];

    if (tid < S) O[qr * S + tid] = scores[tid] * inv_sum;
}

nll_loss.metal_source:
// nll_loss: per-row -sum(y_onehot * log_probs). Output (N,).
#include <metal_stdlib>
using namespace metal;

kernel void nll_loss_f32(
    device const float*  LP       [[buffer(0)]],   // log_probs (N, C)
    device const float*  Yh       [[buffer(1)]],   // one-hot (N, C)
    device       float*  out      [[buffer(2)]],
    constant     uint&   N        [[buffer(3)]],
    constant     uint&   C        [[buffer(4)]],
    uint3 tid3                   [[thread_position_in_threadgroup]],
    uint3 tgid                   [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint row = tgid.y;
    device const float* lp = LP + row * C;
    device const float* yp = Yh + row * C;
    threadgroup float reduce[32];

    float nll = 0.0f;
    for (uint i = tid; i < C; i += TG) nll += -yp[i] * lp[i];
    nll = simd_sum(nll);
    if ((tid & 31) == 0) reduce[tid >> 5] = nll;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        nll = reduce[tid];
        for (uint s = 16; s > 0; s >>= 1) nll += simd_shuffle_down(nll, s);
        if (tid == 0) out[row] = nll;
    }
}

log_softmax_cross_entropy.metal_source:
// log_softmax_cross_entropy: same as cross_entropy_loss, single pass per row.
// Output shape (N,).
#include <metal_stdlib>
using namespace metal;

kernel void log_softmax_cross_entropy_f32(
    device const float*  L        [[buffer(0)]],
    device const float*  Yh       [[buffer(1)]],
    device       float*  out      [[buffer(2)]],
    constant     uint&   N        [[buffer(3)]],
    constant     uint&   C        [[buffer(4)]],
    uint3 tid3                   [[thread_position_in_threadgroup]],
    uint3 tgid                   [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint row = tgid.y;
    device const float* lp = L  + row * C;
    device const float* yp = Yh + row * C;
    threadgroup float reduce[32];

    float mx = -INFINITY;
    for (uint i = tid; i < C; i += TG) mx = fmax(mx, lp[i]);
    mx = simd_max(mx);
    if ((tid & 31) == 0) reduce[tid >> 5] = mx;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        mx = reduce[tid];
        for (uint s = 16; s > 0; s >>= 1) mx = fmax(mx, simd_shuffle_down(mx, s));
        if (tid == 0) reduce[0] = mx;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float row_max = reduce[0];

    float sum = 0.0f;
    for (uint i = tid; i < C; i += TG) sum += exp(lp[i] - row_max);
    sum = simd_sum(sum);
    if ((tid & 31) == 0) reduce[tid >> 5] = sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        sum = reduce[tid];
        for (uint s = 16; s > 0; s >>= 1) sum += simd_shuffle_down(sum, s);
        if (tid == 0) reduce[0] = sum;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float lse = row_max + log(reduce[0]);

    float nll = 0.0f;
    for (uint i = tid; i < C; i += TG) nll += yp[i] * (lse - lp[i]);
    nll = simd_sum(nll);
    if ((tid & 31) == 0) reduce[tid >> 5] = nll;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        nll = reduce[tid];
        for (uint s = 16; s > 0; s >>= 1) nll += simd_shuffle_down(nll, s);
        if (tid == 0) out[row] = nll;
    }
}

gelu_linear.metal_source:
// gelu_linear: y = gelu(x @ W). Fused matmul + erf-GELU in store phase.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

static inline float erf_approx(float z) {
    float t = 1.0f / (1.0f + 0.3275911f * fabs(z));
    float y = 1.0f - (((((1.061405429f * t - 1.453152027f) * t)
              + 1.421413741f) * t - 0.284496736f) * t + 0.254829592f)
              * t * exp(-z * z);
    return copysign(y, z);
}
static inline float4 gelu4(float4 v) {
    const float k = 0.70710678f; // 1/sqrt(2)
    float4 r;
    r.x = 0.5f * v.x * (1.0f + erf_approx(v.x * k));
    r.y = 0.5f * v.y * (1.0f + erf_approx(v.y * k));
    r.z = 0.5f * v.z * (1.0f + erf_approx(v.z * k));
    r.w = 0.5f * v.w * (1.0f + erf_approx(v.w * k));
    return r;
}

constant constexpr uint BM  = 64, BN  = 64, BK  = 16;
constant constexpr uint SM  = 16, SN  = 32;
constant constexpr uint SIMDS_N = BN / SN;
constant constexpr uint MMA_M = SM / 8, MMA_N = SN / 8;
constant constexpr uint PAD = 4, LDA = BK + PAD, LDB = BN + PAD;

kernel void gelu_linear_f32(
    device const float* A   [[buffer(0)]],
    device const float* B   [[buffer(1)]],
    device       float* C   [[buffer(2)]],
    constant     uint&  M   [[buffer(3)]],
    constant     uint&  N   [[buffer(4)]],
    constant     uint&  K   [[buffer(5)]],
    uint2 tgid              [[threadgroup_position_in_grid]],
    uint  sgid              [[simdgroup_index_in_threadgroup]],
    uint  lid               [[thread_index_in_threadgroup]])
{
    threadgroup float shared[2 * BM * LDA + 2 * BK * LDB];
    threadgroup float (*As)[BM * LDA] = (threadgroup float (*)[BM * LDA]) &shared[0];
    threadgroup float (*Bs)[BK * LDB] = (threadgroup float (*)[BK * LDB]) &shared[2 * BM * LDA];
    const uint sm = sgid / SIMDS_N, sn = sgid % SIMDS_N;
    const uint c_row0 = tgid.y * BM, c_col0 = tgid.x * BN;
    const uint a_row = lid / 4, a_c4 = lid % 4, b_row = lid / 16, b_c4 = lid % 16;

    simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

    { // Prologue
        *reinterpret_cast<threadgroup float4*>(&As[0][a_row * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&A[(c_row0 + a_row) * K + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bs[0][b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&B[b_row * N + c_col0 + b_c4 * 4]);
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    const uint num_k_tiles = K / BK; uint buf = 0;

    for (uint kt = 0; kt < num_k_tiles - 1; ++kt) {
        const uint next = 1 - buf, k0_nxt = (kt + 1) * BK;
        *reinterpret_cast<threadgroup float4*>(&As[next][a_row * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&A[(c_row0 + a_row) * K + k0_nxt + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bs[next][b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&B[(k0_nxt + b_row) * N + c_col0 + b_c4 * 4]);
        #pragma unroll
        for (uint kc = 0; kc < BK; kc += 8) {
            simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i) simdgroup_load(A_blk[i], &As[buf][(sm*SM+i*8)*LDA+kc], LDA);
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j) simdgroup_load(B_blk[j], &Bs[buf][kc*LDB+sn*SN+j*8], LDB);
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
        }
        threadgroup_barrier(mem_flags::mem_threadgroup); buf = next;
    }
    #pragma unroll
    for (uint kc = 0; kc < BK; kc += 8) {
        simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i) simdgroup_load(A_blk[i], &As[buf][(sm*SM+i*8)*LDA+kc], LDA);
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j) simdgroup_load(B_blk[j], &Bs[buf][kc*LDB+sn*SN+j*8], LDB);
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
    }

    threadgroup_barrier(mem_flags::mem_threadgroup);
    threadgroup float* Cs = &shared[0];
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            simdgroup_store(C_acc[i][j], &Cs[(sm*SM + i*8) * BN + sn*SN + j*8], BN);
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const uint total_f4 = BM * BN / 4;
    #pragma unroll
    for (uint idx = lid; idx < total_f4; idx += 256) {
        uint r = (idx * 4) / BN;
        uint c = (idx * 4) % BN;
        float4 v = *reinterpret_cast<threadgroup float4*>(&Cs[r * BN + c]);
        *reinterpret_cast<device float4*>(&C[(c_row0 + r) * N + (c_col0 + c)]) = gelu4(v);
    }
}

rms_norm_linear.metal_source:
// rms_norm_linear: y = rms_norm(x) @ W. Two-pass: sumsq reduction, then normalized matmul.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM  = 64, BN  = 64, BK  = 16;
constant constexpr uint SM  = 16, SN  = 32, SIMDS_N = BN / SN;
constant constexpr uint MMA_M = SM / 8, MMA_N = SN / 8;
constant constexpr uint PAD = 4, LDA = BK + PAD, LDB = BN + PAD;

kernel void rms_norm_linear_f32(
    device const float* A   [[buffer(0)]],
    device const float* B   [[buffer(1)]],
    device       float* C   [[buffer(2)]],
    constant     uint&  M   [[buffer(3)]],
    constant     uint&  N   [[buffer(4)]],
    constant     uint&  K   [[buffer(5)]],
    constant     float&  eps [[buffer(6)]],
    uint2 tgid              [[threadgroup_position_in_grid]],
    uint  sgid              [[simdgroup_index_in_threadgroup]],
    uint  lid               [[thread_index_in_threadgroup]])
{
    threadgroup float As[2][BM * LDA], Bs[2][BK * LDB];
    const uint sm = sgid / SIMDS_N, sn = sgid % SIMDS_N;
    const uint c_row0 = tgid.y * BM, c_col0 = tgid.x * BN;
    const uint a_row = lid / 4, a_c4 = lid % 4, b_row = lid / 16, b_c4 = lid % 16;

    // Pass 1: per-row sumsq. RMS norm is per-row of A; we need inv_rms for each
    // row in this BM-tile (a_row in [0, BM)). Each row processed by 4 threads
    // sharing a_row → use float4 accumulators across K, then simd-reduce within
    // the row's 4 threads via lane mask.
    threadgroup float inv_rms_row[BM];
    {
        float acc = 0.0f;
        // 4 threads per row (a_c4 = 0..3) each handle K/4 elements stride 4 floats.
        for (uint k = a_c4 * 4; k < K; k += 16) {
            float4 v = *reinterpret_cast<const device float4*>(&A[(c_row0 + a_row) * K + k]);
            acc += v.x * v.x + v.y * v.y + v.z * v.z + v.w * v.w;
        }
        // Reduce across 4 threads with same a_row. They occupy 4 consecutive lanes
        // within their simd? lid = a_row*4 + a_c4. With simd size 32, lanes 0..31
        // hold a_row=0..7. So 4 threads with same a_row are adjacent.
        acc += simd_shuffle_xor(acc, 1);
        acc += simd_shuffle_xor(acc, 2);
        if (a_c4 == 0) inv_rms_row[a_row] = rsqrt(acc / float(K) + eps);
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float inv_rms = inv_rms_row[a_row];

    // Pass 2: matmul with normalized A
    simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

    {
        float4 v = *reinterpret_cast<const device float4*>(&A[(c_row0 + a_row) * K + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&As[0][a_row*LDA + a_c4*4]) = inv_rms * v;
        // B is (N, K) effectively (we compute A @ B.T). Load Bs[k, n] = B[n, k].
        // b_row in [0, BK), b_c4 in [0, BN/4) → 4 cols of N.
        {
            uint k0 = b_row;
            uint n0 = c_col0 + b_c4 * 4;
            float4 v;
            v.x = B[(n0 + 0) * K + k0];
            v.y = B[(n0 + 1) * K + k0];
            v.z = B[(n0 + 2) * K + k0];
            v.w = B[(n0 + 3) * K + k0];
            *reinterpret_cast<threadgroup float4*>(&Bs[0][b_row*LDB + b_c4*4]) = v;
        }
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    const uint nkt = K / BK; uint buf = 0;

    for (uint kt = 0; kt < nkt - 1; ++kt) {
        const uint next = 1 - buf, k0 = (kt + 1) * BK;
        float4 v = *reinterpret_cast<const device float4*>(&A[(c_row0 + a_row)*K + k0 + a_c4*4]);
        *reinterpret_cast<threadgroup float4*>(&As[next][a_row*LDA + a_c4*4]) = inv_rms * v;
        {
            uint kk = k0 + b_row;
            uint nn = c_col0 + b_c4 * 4;
            float4 v;
            v.x = B[(nn + 0) * K + kk];
            v.y = B[(nn + 1) * K + kk];
            v.z = B[(nn + 2) * K + kk];
            v.w = B[(nn + 3) * K + kk];
            *reinterpret_cast<threadgroup float4*>(&Bs[next][b_row*LDB + b_c4*4]) = v;
        }
        #pragma unroll
        for (uint kc = 0; kc < BK; kc += 8) {
            simdgroup_matrix<float, 8, 8> Ab[MMA_M], Bb[MMA_N];
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i) simdgroup_load(Ab[i], &As[buf][(sm*SM+i*8)*LDA+kc], LDA);
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j) simdgroup_load(Bb[j], &Bs[buf][kc*LDB+sn*SN+j*8], LDB);
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_multiply_accumulate(C_acc[i][j], Ab[i], Bb[j], C_acc[i][j]);
        }
        threadgroup_barrier(mem_flags::mem_threadgroup); buf = next;
    }
    #pragma unroll
    for (uint kc = 0; kc < BK; kc += 8) {
        simdgroup_matrix<float, 8, 8> Ab[MMA_M], Bb[MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i) simdgroup_load(Ab[i], &As[buf][(sm*SM+i*8)*LDA+kc], LDA);
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j) simdgroup_load(Bb[j], &Bs[buf][kc*LDB+sn*SN+j*8], LDB);
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_multiply_accumulate(C_acc[i][j], Ab[i], Bb[j], C_acc[i][j]);
    }

    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            simdgroup_store(C_acc[i][j], &C[(c_row0+sm*SM+i*8)*N+(c_col0+sn*SN+j*8)], N);
}

transformer_block.metal_source:
// transformer_block — pre-LN BERT/ViT block (M4)
// One TG of 1024 threads. S=64 D=128 H=4 Dh=32 FF=256.
//
// Strategy: attention works as before (correct). For FFN, snapshot the
// post-attention residual y as LN2(y) into the entire 32KB pool, then do FFN
// without intermediate state — each (s, d_out) thread streams over FF, computing
// hidden[s,f] = gelu(ln_snap[s,:] · W_ff1[:,f]) and accumulating into y[s,d_out].
#include <metal_stdlib>
using namespace metal;

#define S 64
#define D 128
#define H 4
#define DH 32
#define FF 256
#define TG 1024

kernel void transformer_block_f32(
    device const float* x      [[buffer(0)]],
    device const float* W_qkv  [[buffer(1)]],
    device const float* W_o    [[buffer(2)]],
    device const float* W_ff1  [[buffer(3)]],
    device const float* W_ff2  [[buffer(4)]],
    device       float* y      [[buffer(5)]],
    constant uint& S_  [[buffer(6)]],
    constant uint& D_  [[buffer(7)]],
    constant uint& H_  [[buffer(8)]],
    constant uint& FF_ [[buffer(9)]],
    constant float& eps [[buffer(10)]],
    uint3 tid [[thread_position_in_threadgroup]])
{
    const uint t = tid.x;
    threadgroup float pool[8192];                  // 32 KB
    threadgroup float* means = pool;
    threadgroup float* rstds = pool + 64;
    threadgroup float* Qh = pool + 128;
    threadgroup float* Kh = pool + 128 + 2048;
    threadgroup float* Vh = pool + 128 + 4096;
    threadgroup float* sc = pool + 128;            // alias for Qh+Kh during attention

    // y = x
    for (uint i = t; i < S*D; i += TG) y[i] = x[i];
    threadgroup_barrier(mem_flags::mem_threadgroup | mem_flags::mem_device);

    // LN1 stats from x
    {
        const uint row = t >> 4;
        const uint lane = t & 15;
        const uint off = row * D;
        float s1 = 0, s2 = 0;
        for (uint d = lane; d < D; d += 16) {
            float v = x[off + d]; s1 += v; s2 += v*v;
        }
        s1 += simd_shuffle_xor(s1, 1);
        s1 += simd_shuffle_xor(s1, 2);
        s1 += simd_shuffle_xor(s1, 4);
        s1 += simd_shuffle_xor(s1, 8);
        s2 += simd_shuffle_xor(s2, 1);
        s2 += simd_shuffle_xor(s2, 2);
        s2 += simd_shuffle_xor(s2, 4);
        s2 += simd_shuffle_xor(s2, 8);
        if (lane == 0) {
            float m = s1 / float(D);
            float v = max(s2/float(D) - m*m, 0.0f);
            means[row] = m;
            rstds[row] = rsqrt(v + eps);
        }
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Attention per head
    const float inv_sqrt_dh = rsqrt(float(DH));
    for (uint h = 0; h < H; ++h) {
        for (uint idx = t; idx < S*DH; idx += TG) {
            uint s = idx / DH;
            uint dh = idx % DH;
            uint off = s * D;
            float m = means[s], rs = rstds[s];
            float qa = 0, ka = 0, va = 0;
            for (uint d = 0; d < D; ++d) {
                float ln = (x[off + d] - m) * rs;
                qa += ln * W_qkv[d*(3u*D) + h*DH + dh];
                ka += ln * W_qkv[d*(3u*D) + D + h*DH + dh];
                va += ln * W_qkv[d*(3u*D) + 2u*D + h*DH + dh];
            }
            Qh[idx] = qa; Kh[idx] = ka; Vh[idx] = va;
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);

        float my_sc[4];
        for (uint pi = 0; pi < 4; ++pi) {
            uint pair = t*4 + pi;
            uint sq = pair / S;
            uint kt = pair % S;
            float dot = 0;
            for (uint d = 0; d < DH; ++d) dot += Qh[sq*DH + d] * Kh[kt*DH + d];
            my_sc[pi] = dot * inv_sqrt_dh;
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
        for (uint pi = 0; pi < 4; ++pi) sc[t*4 + pi] = my_sc[pi];
        threadgroup_barrier(mem_flags::mem_threadgroup);

        {
            uint sq = t >> 4; uint lane = t & 15;
            uint base = sq * S;
            float v0 = sc[base + lane];
            float v1 = sc[base + lane + 16];
            float v2 = sc[base + lane + 32];
            float v3 = sc[base + lane + 48];
            float m = max(max(v0,v1), max(v2,v3));
            m = max(m, simd_shuffle_xor(m, 1));
            m = max(m, simd_shuffle_xor(m, 2));
            m = max(m, simd_shuffle_xor(m, 4));
            m = max(m, simd_shuffle_xor(m, 8));
            v0 = exp(v0-m); v1 = exp(v1-m); v2 = exp(v2-m); v3 = exp(v3-m);
            float ss = v0+v1+v2+v3;
            ss += simd_shuffle_xor(ss, 1);
            ss += simd_shuffle_xor(ss, 2);
            ss += simd_shuffle_xor(ss, 4);
            ss += simd_shuffle_xor(ss, 8);
            float inv = 1.0f / ss;
            sc[base + lane]    = v0 * inv;
            sc[base + lane+16] = v1 * inv;
            sc[base + lane+32] = v2 * inv;
            sc[base + lane+48] = v3 * inv;
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);

        float oh_vals[2]; uint oh_idx[2]; uint nn = 0;
        for (uint idx = t; idx < S*DH; idx += TG) {
            uint sq = idx / DH;
            uint dh = idx % DH;
            float acc = 0;
            for (uint k = 0; k < S; ++k) acc += sc[sq*S + k] * Vh[k*DH + dh];
            oh_vals[nn] = acc; oh_idx[nn] = idx; nn++;
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
        for (uint i = 0; i < nn; ++i) sc[oh_idx[i]] = oh_vals[i];
        threadgroup_barrier(mem_flags::mem_threadgroup);

        for (uint idx = t; idx < S*D; idx += TG) {
            uint sr = idx / D;
            uint dout = idx % D;
            float acc = 0;
            for (uint dh = 0; dh < DH; ++dh) {
                acc += sc[sr*DH + dh] * W_o[(h*DH + dh)*D + dout];
            }
            y[sr*D + dout] += acc;
        }
        threadgroup_barrier(mem_flags::mem_threadgroup | mem_flags::mem_device);
    }

    // ===== FFN =====
    // 1) compute LN2 stats from y and store ln_snap[s, d] in pool (overwriting Q/K/V)
    threadgroup float* ln_snap = pool;              // [S*D = 8192] uses full pool
    // we lose means/rstds; recompute on the fly per row

    // Compute means/rstds and ln_snap[s,d] = (y[s,d] - m) * rstd
    // Distribute: 16 threads per row, each handling D/16 = 8 elements.
    {
        const uint row = t >> 4;
        const uint lane = t & 15;
        const uint off = row * D;
        // each lane handles d = lane, lane+16, ..., lane+112 (8 elements)
        float v[8];
        float s1 = 0, s2 = 0;
        for (uint i = 0; i < 8; ++i) {
            v[i] = y[off + lane + i*16];
            s1 += v[i];
            s2 += v[i]*v[i];
        }
        s1 += simd_shuffle_xor(s1, 1);
        s1 += simd_shuffle_xor(s1, 2);
        s1 += simd_shuffle_xor(s1, 4);
        s1 += simd_shuffle_xor(s1, 8);
        s2 += simd_shuffle_xor(s2, 1);
        s2 += simd_shuffle_xor(s2, 2);
        s2 += simd_shuffle_xor(s2, 4);
        s2 += simd_shuffle_xor(s2, 8);
        float m = s1 / float(D);
        float var = max(s2/float(D) - m*m, 0.0f);
        float rs = rsqrt(var + eps);
        for (uint i = 0; i < 8; ++i) {
            ln_snap[off + lane + i*16] = (v[i] - m) * rs;
        }
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // 2) FFN — no tiling. Each (s, d_out) thread accumulates over the full FF axis.
    //    Distribute: 1024 threads cover S*D = 8192 cells, 8 per thread.
    //    For each (s, d_out), compute:
    //      acc = sum_{f=0..FF-1} gelu(ln_snap[s,:] · W_ff1[:, f]) * W_ff2[f, d_out]
    //    Inner work per thread cell: FF * (D + 1) ~= 256 * 129 = 33024 ops.
    //    With 8 cells/thread, total = 264K ops/thread. Fine.
    //
    //    To avoid recomputing gelu(ln_snap[s,:]·W_ff1[:,f]) across all d_out for
    //    same s, we precompute hidden[s,f] for the SAME s grouped threads.
    //    Even better: each thread handles a (s, d_out_chunk). For each thread,
    //    s is fixed across its 8 cells (if we layout as (s, d_chunk)). Then for
    //    each f we compute hidden_f ONCE for this s and reuse across the 8 cells.
    //
    //    Layout: thread t handles (s = t / 16, d_out_chunk = t % 16). Each thread
    //    covers d_out = chunk*8 + [0..7] (8 outputs) for one row s. Reuse hidden_f.
    {
        const uint s = t / 16;
        const uint dchunk = t & 15;       // 0..15
        const uint d_out_base = dchunk * 8;

        // accumulator for 8 outputs
        float out_acc[8];
        for (uint i = 0; i < 8; ++i) out_acc[i] = 0.0f;

        // load ln_snap[s, :] into thread registers... 128 floats too many. Stream from tg.
        for (uint f = 0; f < FF; ++f) {
            // hidden_f = sum_d ln_snap[s, d] * W_ff1[d, f]
            float h_acc = 0.0f;
            for (uint d = 0; d < D; ++d) {
                h_acc += ln_snap[s*D + d] * W_ff1[d*FF + f];
            }
            // GELU(h_acc)
            // tanh approx GELU
            float k0 = 0.7978845608028654f;
            float k1 = 0.044715f;
            float gel = 0.5f * h_acc * (1.0f + precise::tanh(k0 * (h_acc + k1 * h_acc * h_acc * h_acc)));

            // accumulate into 8 outputs
            for (uint i = 0; i < 8; ++i) {
                uint d_out = d_out_base + i;
                out_acc[i] += gel * W_ff2[f*D + d_out];
            }
        }
        // write y += out_acc
        for (uint i = 0; i < 8; ++i) {
            y[s*D + d_out_base + i] += out_acc[i];
        }
    }
}

llama_attention.metal_source:
// llama_attention: GQA + RoPE attention (no KV cache, no LN).
// S=64 D=128 H=4 H_kv=2 D_head=32 (G = H/H_kv = 2)
// One TG of 1024 threads, 16 threads per query row.
#include <metal_stdlib>
using namespace metal;

#define S    64
#define D    128
#define HH   4
#define HKV  2
#define DH   32
#define G    2
#define TG   1024

kernel void llama_attention_f32(
    device const float* x      [[buffer(0)]],
    device const float* W_qkv  [[buffer(1)]],
    device const float* W_o    [[buffer(2)]],
    device       float* y      [[buffer(3)]],
    constant uint& S_   [[buffer(4)]],
    constant uint& D_   [[buffer(5)]],
    constant uint& H_   [[buffer(6)]],
    constant uint& Hkv_ [[buffer(7)]],
    constant float& base [[buffer(8)]],
    uint3 tid [[thread_position_in_threadgroup]])
{
    const uint t = tid.x;
    constexpr uint QKV_W = D + 2u * HKV * DH;   // 256

    threadgroup float Kh[S * DH];
    threadgroup float Vh[S * DH];
    threadgroup float oh[S * DH];

    const float inv_sqrt_dh = rsqrt(float(DH));
    const float two_over_dh = 2.0f / float(DH);

    for (uint kvh = 0; kvh < HKV; ++kvh) {
        // K, V projection (with RoPE on K).
        {
            const uint sr   = t >> 4;
            const uint lane = t & 15;
            const uint off  = sr * D;
            const uint i_pair = lane;
            const uint dh0 = 2 * i_pair;
            const uint dh1 = dh0 + 1;
            const uint colK0 = D + kvh*DH + dh0;
            const uint colK1 = D + kvh*DH + dh1;
            const uint colV0 = D + HKV*DH + kvh*DH + dh0;
            const uint colV1 = D + HKV*DH + kvh*DH + dh1;
            float k0 = 0.f, k1 = 0.f, v0 = 0.f, v1 = 0.f;
            for (uint d = 0; d < D; ++d) {
                float xv = x[off + d];
                k0 += xv * W_qkv[d*QKV_W + colK0];
                k1 += xv * W_qkv[d*QKV_W + colK1];
                v0 += xv * W_qkv[d*QKV_W + colV0];
                v1 += xv * W_qkv[d*QKV_W + colV1];
            }
            float pos = float(sr);
            float omega = precise::pow(base, -two_over_dh * float(i_pair));
            float ang = pos * omega;
            float c = precise::cos(ang), s_ = precise::sin(ang);
            Kh[sr*DH + dh0] = k0 * c - k1 * s_;
            Kh[sr*DH + dh1] = k0 * s_ + k1 * c;
            Vh[sr*DH + dh0] = v0;
            Vh[sr*DH + dh1] = v1;
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);

        for (uint h_off = 0; h_off < G; ++h_off) {
            const uint h = kvh * G + h_off;
            {
                const uint sq   = t >> 4;
                const uint lane = t & 15;
                const uint off  = sq * D;
                const uint i_pair = lane;
                const uint dh0 = 2 * i_pair;
                const uint dh1 = dh0 + 1;
                const uint colQ0 = h*DH + dh0;
                const uint colQ1 = h*DH + dh1;
                float q0 = 0.f, q1 = 0.f;
                for (uint d = 0; d < D; ++d) {
                    float xv = x[off + d];
                    q0 += xv * W_qkv[d*QKV_W + colQ0];
                    q1 += xv * W_qkv[d*QKV_W + colQ1];
                }
                float pos = float(sq);
                float omega = precise::pow(base, -two_over_dh * float(i_pair));
                float ang = pos * omega;
                float c = precise::cos(ang), s_ = precise::sin(ang);
                float q0r = q0 * c - q1 * s_;
                float q1r = q0 * s_ + q1 * c;

                float out0 = 0.f, out1 = 0.f;
                float m_run = -INFINITY;
                float l_run = 0.f;
                for (uint kt = 0; kt < S; ++kt) {
                    float ka = Kh[kt*DH + dh0];
                    float kb = Kh[kt*DH + dh1];
                    float partial = q0r * ka + q1r * kb;
                    partial += simd_shuffle_xor(partial, 1);
                    partial += simd_shuffle_xor(partial, 2);
                    partial += simd_shuffle_xor(partial, 4);
                    partial += simd_shuffle_xor(partial, 8);
                    float score = partial * inv_sqrt_dh;
                    float mn = max(m_run, score);
                    float alpha = exp(m_run - mn);
                    float beta  = exp(score - mn);
                    out0 = out0 * alpha + beta * Vh[kt*DH + dh0];
                    out1 = out1 * alpha + beta * Vh[kt*DH + dh1];
                    l_run = l_run * alpha + beta;
                    m_run = mn;
                }
                float inv = 1.0f / l_run;
                oh[sq*DH + dh0] = out0 * inv;
                oh[sq*DH + dh1] = out1 * inv;
            }
            threadgroup_barrier(mem_flags::mem_threadgroup);

            for (uint idx = t; idx < S*D; idx += TG) {
                const uint sr   = idx / D;
                const uint dout = idx % D;
                float acc = 0.f;
                for (uint dh = 0; dh < DH; ++dh) {
                    acc += oh[sr*DH + dh] * W_o[(h*DH + dh)*D + dout];
                }
                if (kvh == 0 && h_off == 0) {
                    y[sr*D + dout] = acc;
                } else {
                    y[sr*D + dout] += acc;
                }
            }
            threadgroup_barrier(mem_flags::mem_threadgroup | mem_flags::mem_device);
        }
    }
}

llama_decoder_layer.metal_source:
// llama_decoder_layer: RMSNorm + GQA(+RoPE) + residual + RMSNorm + SwiGLU FFN + residual.
// S=64 D=128 H=4 H_kv=2 D_head=32 FF=256 (G = H/H_kv = 2). One TG of 1024 threads.
#include <metal_stdlib>
using namespace metal;

#define S    64
#define D    128
#define HH   4
#define HKV  2
#define DH   32
#define G    2
#define FF   256
#define TG   1024

inline float silu(float v) { return v / (1.0f + exp(-v)); }

kernel void llama_decoder_layer_f32(
    device const float* x      [[buffer(0)]],
    device const float* W_qkv  [[buffer(1)]],
    device const float* W_o    [[buffer(2)]],
    device const float* W_gu   [[buffer(3)]],
    device const float* W_down [[buffer(4)]],
    device       float* y      [[buffer(5)]],
    constant uint& S_   [[buffer(6)]],
    constant uint& D_   [[buffer(7)]],
    constant uint& H_   [[buffer(8)]],
    constant uint& Hkv_ [[buffer(9)]],
    constant uint& FF_  [[buffer(10)]],
    constant float& base [[buffer(11)]],
    constant float& eps  [[buffer(12)]],
    uint3 tid [[thread_position_in_threadgroup]])
{
    const uint t = tid.x;
    constexpr uint QKV_W = D + 2u * HKV * DH;
    constexpr uint GU_W  = 2u * FF;

    threadgroup float rstd[S];                  // 64
    threadgroup float Kh[S * DH];               // 2048
    threadgroup float Vh[S * DH];               // 2048
    threadgroup float oh[S * DH];               // 2048
    // Total: 64 + 6144 = 6208 floats = ~24.5 KB
    // After attention: reuse Kh + Vh + oh as ff_out (6144 floats covers most of y; need 8192).
    // For FFN we accumulate into y itself by computing one row at a time (no y-read/write race).

    const float inv_sqrt_dh = rsqrt(float(DH));
    const float two_over_dh = 2.0f / float(DH);

    // RMSNorm rstd over x.
    {
        const uint sr   = t >> 4;
        const uint lane = t & 15;
        const uint off  = sr * D;
        float s2 = 0.f;
        for (uint d = lane; d < D; d += 16) {
            float v = x[off + d];
            s2 += v * v;
        }
        s2 += simd_shuffle_xor(s2, 1);
        s2 += simd_shuffle_xor(s2, 2);
        s2 += simd_shuffle_xor(s2, 4);
        s2 += simd_shuffle_xor(s2, 8);
        if (lane == 0) rstd[sr] = rsqrt(s2 / float(D) + eps);
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // y = x.
    for (uint i = t; i < S*D; i += TG) y[i] = x[i];
    threadgroup_barrier(mem_flags::mem_threadgroup | mem_flags::mem_device);

    // GQA attention.
    for (uint kvh = 0; kvh < HKV; ++kvh) {
        // K, V projection + RoPE on K.
        {
            const uint sr   = t >> 4;
            const uint lane = t & 15;
            const uint off  = sr * D;
            const uint i_pair = lane;
            const uint dh0 = 2 * i_pair;
            const uint dh1 = dh0 + 1;
            const uint colK0 = D + kvh*DH + dh0;
            const uint colK1 = D + kvh*DH + dh1;
            const uint colV0 = D + HKV*DH + kvh*DH + dh0;
            const uint colV1 = D + HKV*DH + kvh*DH + dh1;
            const float rs = rstd[sr];
            float k0 = 0.f, k1 = 0.f, v0 = 0.f, v1 = 0.f;
            for (uint d = 0; d < D; ++d) {
                float ln = x[off + d] * rs;
                k0 += ln * W_qkv[d*QKV_W + colK0];
                k1 += ln * W_qkv[d*QKV_W + colK1];
                v0 += ln * W_qkv[d*QKV_W + colV0];
                v1 += ln * W_qkv[d*QKV_W + colV1];
            }
            float omega = precise::pow(base, -two_over_dh * float(i_pair));
            float ang = float(sr) * omega;
            float c = precise::cos(ang), s_ = precise::sin(ang);
            Kh[sr*DH + dh0] = k0 * c - k1 * s_;
            Kh[sr*DH + dh1] = k0 * s_ + k1 * c;
            Vh[sr*DH + dh0] = v0;
            Vh[sr*DH + dh1] = v1;
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);

        for (uint h_off = 0; h_off < G; ++h_off) {
            const uint h = kvh * G + h_off;
            {
                const uint sq   = t >> 4;
                const uint lane = t & 15;
                const uint off  = sq * D;
                const uint i_pair = lane;
                const uint dh0 = 2 * i_pair;
                const uint dh1 = dh0 + 1;
                const uint colQ0 = h*DH + dh0;
                const uint colQ1 = h*DH + dh1;
                const float rs = rstd[sq];
                float q0 = 0.f, q1 = 0.f;
                for (uint d = 0; d < D; ++d) {
                    float ln = x[off + d] * rs;
                    q0 += ln * W_qkv[d*QKV_W + colQ0];
                    q1 += ln * W_qkv[d*QKV_W + colQ1];
                }
                float omega = precise::pow(base, -two_over_dh * float(i_pair));
                float ang = float(sq) * omega;
                float c = precise::cos(ang), s_ = precise::sin(ang);
                float q0r = q0 * c - q1 * s_;
                float q1r = q0 * s_ + q1 * c;

                float out0 = 0.f, out1 = 0.f;
                float m_run = -INFINITY;
                float l_run = 0.f;
                for (uint kt = 0; kt < S; ++kt) {
                    float ka = Kh[kt*DH + dh0];
                    float kb = Kh[kt*DH + dh1];
                    float partial = q0r * ka + q1r * kb;
                    partial += simd_shuffle_xor(partial, 1);
                    partial += simd_shuffle_xor(partial, 2);
                    partial += simd_shuffle_xor(partial, 4);
                    partial += simd_shuffle_xor(partial, 8);
                    float score = partial * inv_sqrt_dh;
                    float mn = max(m_run, score);
                    float alpha = exp(m_run - mn);
                    float beta  = exp(score - mn);
                    out0 = out0 * alpha + beta * Vh[kt*DH + dh0];
                    out1 = out1 * alpha + beta * Vh[kt*DH + dh1];
                    l_run = l_run * alpha + beta;
                    m_run = mn;
                }
                float inv = 1.0f / l_run;
                oh[sq*DH + dh0] = out0 * inv;
                oh[sq*DH + dh1] = out1 * inv;
            }
            threadgroup_barrier(mem_flags::mem_threadgroup);

            for (uint idx = t; idx < S*D; idx += TG) {
                const uint sr   = idx / D;
                const uint dout = idx % D;
                float acc = 0.f;
                for (uint dh = 0; dh < DH; ++dh) {
                    acc += oh[sr*DH + dh] * W_o[(h*DH + dh)*D + dout];
                }
                y[sr*D + dout] += acc;
            }
            threadgroup_barrier(mem_flags::mem_threadgroup | mem_flags::mem_device);
        }
    }

    // RMSNorm rstd over y.
    {
        const uint sr   = t >> 4;
        const uint lane = t & 15;
        const uint off  = sr * D;
        float s2 = 0.f;
        for (uint d = lane; d < D; d += 16) {
            float v = y[off + d];
            s2 += v * v;
        }
        s2 += simd_shuffle_xor(s2, 1);
        s2 += simd_shuffle_xor(s2, 2);
        s2 += simd_shuffle_xor(s2, 4);
        s2 += simd_shuffle_xor(s2, 8);
        if (lane == 0) rstd[sr] = rsqrt(s2 / float(D) + eps);
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Row-serial SwiGLU FFN — avoids the y-read/y-write race across tiles.
    // We have Kh+Vh+oh = 6144 floats available (attention done).
    // Per-row buffers:
    //   ln_row[D=128]      = LN(y)[sr, :]
    //   tile[FF=256]       = silu(gate)*up for this row
    // Total per row: 384 floats. Use the start of Kh.
    threadgroup float* ln_row = Kh;          // [D]
    threadgroup float* tile   = Kh + D;      // [FF]

    for (uint sr = 0; sr < S; ++sr) {
        const float rs = rstd[sr];
        const uint row_off = sr * D;

        // Load ln_row.
        for (uint d = t; d < D; d += TG) {
            ln_row[d] = y[row_off + d] * rs;
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);

        // tile[f] = silu(gate)*up; one thread per f.
        for (uint f = t; f < FF; f += TG) {
            float gate_acc = 0.f, up_acc = 0.f;
            for (uint d = 0; d < D; ++d) {
                float ln = ln_row[d];
                gate_acc += ln * W_gu[d*GU_W + f];
                up_acc   += ln * W_gu[d*GU_W + FF + f];
            }
            tile[f] = silu(gate_acc) * up_acc;
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);

        // y[sr, d_out] += sum_f tile[f] * W_down[f, d_out]; one thread per d_out (D=128).
        for (uint d_out = t; d_out < D; d_out += TG) {
            float acc = 0.f;
            for (uint f = 0; f < FF; ++f) {
                acc += tile[f] * W_down[f*D + d_out];
            }
            y[row_off + d_out] += acc;
        }
        threadgroup_barrier(mem_flags::mem_threadgroup | mem_flags::mem_device);
    }
}

rsqrt.metal_source:
#include <metal_stdlib>
using namespace metal;

kernel void rsqrt_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    for (uint i = tid; i < N; i += grid_size) {
        y[i] = rsqrt(fabs(x[i]));
    }
}

conv1d.metal_source:
// conv1d: direct NLC convolution. x (N,L,C_in), w (C_out,R,C_in), y (N,L2,C_out).
#include <metal_stdlib>
using namespace metal;

kernel void conv1d_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  w       [[buffer(1)]],
    device       float*  y       [[buffer(2)]],
    constant     uint&   N       [[buffer(3)]],
    constant     uint&   C       [[buffer(4)]],
    constant     uint&   L       [[buffer(5)]],
    constant     uint&   K       [[buffer(6)]],
    constant     uint&   R       [[buffer(7)]],
    constant     uint&   stride  [[buffer(8)]],
    uint tid [[thread_position_in_grid]])
{
    const uint L2 = (L - R) / stride + 1;
    const uint total = N * L2 * K;
    for (uint idx = tid; idx < total; idx += 64 * 1024) {
        uint n = idx / (L2 * K), p = idx % (L2 * K);
        uint l2 = p / K, k = p % K;
        float sum = 0;
        for (uint rr = 0; rr < R; ++rr)
            for (uint c = 0; c < C; ++c)
                sum += x[(n * L + l2 * stride + rr) * C + c] * w[(k * R + rr) * C + c];
        y[(n * L2 + l2) * K + k] = sum;
    }
}

conv3d.metal_source:
// conv3d: direct NDHWC convolution. x (N,D,H,W,C_in), w (C_out,R,R,R,C_in).
#include <metal_stdlib>
using namespace metal;

kernel void conv3d_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  w       [[buffer(1)]],
    device       float*  y       [[buffer(2)]],
    constant     uint&   N       [[buffer(3)]],
    constant     uint&   C       [[buffer(4)]],
    constant     uint&   D       [[buffer(5)]],
    constant     uint&   H       [[buffer(6)]],
    constant     uint&   W       [[buffer(7)]],
    constant     uint&   K       [[buffer(8)]],
    constant     uint&   R       [[buffer(9)]],
    constant     uint&   stride  [[buffer(10)]],
    uint tid [[thread_position_in_grid]])
{
    const uint D2 = (D - R) / stride + 1;
    const uint H2 = (H - R) / stride + 1;
    const uint W2 = (W - R) / stride + 1;
    const uint total = N * D2 * H2 * W2 * K;
    for (uint idx = tid; idx < total; idx += 64 * 1024) {
        uint q = idx;
        uint n = q / (D2 * H2 * W2 * K);   q %= (D2 * H2 * W2 * K);
        uint d2 = q / (H2 * W2 * K);       q %= (H2 * W2 * K);
        uint h2 = q / (W2 * K);            q %= (W2 * K);
        uint w2 = q / K;
        uint k  = q % K;
        float sum = 0;
        for (uint rd = 0; rd < R; ++rd)
            for (uint rh = 0; rh < R; ++rh)
                for (uint rw = 0; rw < R; ++rw)
                    for (uint c = 0; c < C; ++c)
                        sum += x[(((n * D + d2 * stride + rd) * H + h2 * stride + rh) * W + w2 * stride + rw) * C + c]
                             * w[(((k * R + rd) * R + rh) * R + rw) * C + c];
        y[(((n * D2 + d2) * H2 + h2) * W2 + w2) * K + k] = sum;
    }
}

depthwise_conv2d.metal_source:
// depthwise_conv2d: NHWC, groups == C. x (N,H,W,C), w (C,R,S,1), y (N,H2,W2,C).
#include <metal_stdlib>
using namespace metal;

kernel void depthwise_conv2d_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  w       [[buffer(1)]],
    device       float*  y       [[buffer(2)]],
    constant     uint&   N       [[buffer(3)]],
    constant     uint&   C       [[buffer(4)]],
    constant     uint&   H       [[buffer(5)]],
    constant     uint&   W       [[buffer(6)]],
    constant     uint&   R       [[buffer(7)]],
    constant     uint&   S       [[buffer(8)]],
    constant     uint&   stride  [[buffer(9)]],
    uint tid [[thread_position_in_grid]])
{
    const uint H2 = (H - R) / stride + 1;
    const uint W2 = (W - S) / stride + 1;
    const uint total = N * H2 * W2 * C;
    for (uint idx = tid; idx < total; idx += 64 * 1024) {
        uint q = idx;
        uint n = q / (H2 * W2 * C);  q %= (H2 * W2 * C);
        uint h2 = q / (W2 * C);      q %= (W2 * C);
        uint w2 = q / C;
        uint c = q % C;
        float sum = 0;
        for (uint rr = 0; rr < R; ++rr)
            for (uint ss = 0; ss < S; ++ss)
                sum += x[((n * H + h2 * stride + rr) * W + w2 * stride + ss) * C + c]
                     * w[(c * R + rr) * S + ss];
        y[((n * H2 + h2) * W2 + w2) * C + c] = sum;
    }
}

conv_transpose2d.metal_source:
// conv_transpose2d: NHWC. x (N,H,W,C_in), w (C_out,R,S,C_in), y (N,H_out,W_out,C_out).
// H_out = (H-1)*stride + R; same for W.
#include <metal_stdlib>
using namespace metal;

kernel void conv_transpose2d_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  w       [[buffer(1)]],
    device       float*  y       [[buffer(2)]],
    constant     uint&   N       [[buffer(3)]],
    constant     uint&   C_in    [[buffer(4)]],
    constant     uint&   H       [[buffer(5)]],
    constant     uint&   W       [[buffer(6)]],
    constant     uint&   C_out   [[buffer(7)]],
    constant     uint&   R       [[buffer(8)]],
    constant     uint&   stride  [[buffer(9)]],
    uint tid [[thread_position_in_grid]])
{
    const uint H_out = (H - 1) * stride + R;
    const uint W_out = (W - 1) * stride + R;
    const uint total = N * H_out * W_out * C_out;
    for (uint idx = tid; idx < total; idx += 64 * 1024) {
        uint q = idx;
        uint n = q / (H_out * W_out * C_out);  q %= (H_out * W_out * C_out);
        uint h_out = q / (W_out * C_out);      q %= (W_out * C_out);
        uint w_out = q / C_out;
        uint k = q % C_out;
        float sum = 0;
        for (uint r = 0; r < R; ++r) {
            int h_in_signed = int(h_out) - int(r);
            if (h_in_signed < 0 || h_in_signed % int(stride) != 0) continue;
            uint h = uint(h_in_signed) / stride;
            if (h >= H) continue;
            for (uint s = 0; s < R; ++s) {
                int w_in_signed = int(w_out) - int(s);
                if (w_in_signed < 0 || w_in_signed % int(stride) != 0) continue;
                uint wi = uint(w_in_signed) / stride;
                if (wi >= W) continue;
                for (uint c = 0; c < C_in; ++c)
                    sum += x[((n * H + h) * W + wi) * C_in + c]
                         * w[((k * R + r) * R + s) * C_in + c];
            }
        }
        y[((n * H_out + h_out) * W_out + w_out) * C_out + k] = sum;
    }
}
